import{_ as t,o as e,c as l,a2 as r}from"./chunks/framework.ZhLefgN8.js";const p=JSON.parse('{"title":"个股 F10 资料","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/stock-f10.md","filePath":"zh-CN/market-data/stock-f10.md"}'),i={name:"market-data/stock-f10.md"};function o(d,a,h,n,s,c){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="个股-f10-资料" tabindex="-1">个股 F10 资料 <a class="header-anchor" href="#个股-f10-资料" aria-label="Permalink to &quot;个股 F10 资料&quot;">​</a></h1><p>F10 是个股基本面资料的统称，在长桥 App 中通过个股详情页的「全景」标签查看。提供上市公司的公司概况、财务数据、股东信息、分红记录等全方位基本面信息，帮助投资者深入了解和分析公司。</p><p>入口：长桥 App - 个股详情页 - 全景</p><h2 id="公司概况" tabindex="-1">公司概况 <a class="header-anchor" href="#公司概况" aria-label="Permalink to &quot;公司概况&quot;">​</a></h2><ul><li>公司简介：公司主营业务、成立时间、注册地、上市日期等基本信息</li><li>行业分类：所属行业板块</li><li>管理层信息：高管团队和董事会成员</li><li>联系方式：公司地址、官网、投资者关系联系方式</li></ul><h2 id="财务数据" tabindex="-1">财务数据 <a class="header-anchor" href="#财务数据" aria-label="Permalink to &quot;财务数据&quot;">​</a></h2><p>长桥 App 提供三大财务报表的深度分析，涵盖 30+ 核心财务指标。</p><h3 id="利润表" tabindex="-1">利润表 <a class="header-anchor" href="#利润表" aria-label="Permalink to &quot;利润表&quot;">​</a></h3><p>展示公司营业收入、净利润、毛利率、净利率等盈利指标，可查看季度和年度数据。</p><h3 id="资产负债表" tabindex="-1">资产负债表 <a class="header-anchor" href="#资产负债表" aria-label="Permalink to &quot;资产负债表&quot;">​</a></h3><p>展示公司总资产、总负债、股东权益、资产负债率等资产状况。</p><h3 id="现金流量表" tabindex="-1">现金流量表 <a class="header-anchor" href="#现金流量表" aria-label="Permalink to &quot;现金流量表&quot;">​</a></h3><p>展示经营活动、投资活动、筹资活动的现金流入流出情况。</p><h3 id="核心财务指标" tabindex="-1">核心财务指标 <a class="header-anchor" href="#核心财务指标" aria-label="Permalink to &quot;核心财务指标&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类别</th><th>主要指标</th></tr></thead><tbody><tr><td>盈利能力</td><td>每股收益（EPS）、净利润、毛利率、净利率、ROE、ROA</td></tr><tr><td>估值指标</td><td>市盈率（PE TTM/动态/静态）、市净率（PB）、市销率（PS）</td></tr><tr><td>偿债能力</td><td>资产负债率、流动比率、速动比率</td></tr><tr><td>成长能力</td><td>营收增长率、净利润增长率</td></tr></tbody></table><p>详细字段解释请参考 <a href="./行情数据字段介绍">行情数据字段介绍</a>。</p><h2 id="股东信息" tabindex="-1">股东信息 <a class="header-anchor" href="#股东信息" aria-label="Permalink to &quot;股东信息&quot;">​</a></h2><ul><li>股本结构：总股本、流通股本</li><li>主要股东：前十大股东持股比例</li><li>机构持仓：机构投资者持仓变动</li></ul><h2 id="分红信息" tabindex="-1">分红信息 <a class="header-anchor" href="#分红信息" aria-label="Permalink to &quot;分红信息&quot;">​</a></h2><ul><li>历史分红记录：派息日期、每股股息金额、股息率</li><li>分红方式：现金派息、送股、选股选息</li><li>除权除息日、登记日、派息日等关键日期</li></ul><p>查看路径：个股详情页 - 全景 - 百科 - 分红</p><h2 id="分析师评级" tabindex="-1">分析师评级 <a class="header-anchor" href="#分析师评级" aria-label="Permalink to &quot;分析师评级&quot;">​</a></h2><ul><li>目标价：分析师给出的目标价格区间</li><li>评级分布：买入、增持、中性、减持、卖出的数量分布</li><li>评级变动：近期分析师评级调整情况</li></ul><h2 id="公司公告与新闻" tabindex="-1">公司公告与新闻 <a class="header-anchor" href="#公司公告与新闻" aria-label="Permalink to &quot;公司公告与新闻&quot;">​</a></h2><ul><li>公司公告：财报发布、公司行动、重大事项公告</li><li>相关新闻：与该公司相关的市场新闻和资讯</li><li>社区讨论：投资者社区中关于该股票的讨论</li></ul><h2 id="portai-智能助手" tabindex="-1">PortAI 智能助手 <a class="header-anchor" href="#portai-智能助手" aria-label="Permalink to &quot;PortAI 智能助手&quot;">​</a></h2><p>长桥 App 内置 PortAI 智能信息助手，可通过对话方式获取个股相关信息，包括财务分析、行业对比、公司行动解读等，帮助高效理解投资信息。</p>',27)])])}const b=t(i,[["render",o]]);export{p as __pageData,b as default};
